const { GSDKnowledgeSync } = require('./src/gsd-qdrant-template.js');
const { applyRecencyBoost } = require('./src/re-ranking');

async function main() {
  const sync = new GSDKnowledgeSync();
  await sync.init();

  // Search for 'intent detector' and get raw hits with lastModified
  const vector = await sync.embedText('intent detector');
  const hits = await sync.client.search(sync.collectionName, { 
    vector: { name: sync.vectorName, vector }, 
    limit: 20,
    with_payload: true, 
    with_vector: false
  });

  console.log('Raw Qdrant results:', hits.length);

  // Map to result objects (same as cli.js does)
  let rankedResults = hits.map(hit => ({ ...hit.payload, score: hit.score, _query: 'intent detector' }));

  // Show before re-ranking
  console.log('\n--- Before Re-Ranking ---');
  for (let i = 0; i < Math.min(5, rankedResults.length); i++) {
    const r = rankedResults[i];
    console.log(\`[\${i}] score=\${r.score.toFixed(4)} source=\${r.source} lastModified=\${r.lastModified || 'N/A'}\`);
  }

  // Apply re-ranking
  applyRecencyBoost(rankedResults, { days: 30, pathMatch: true });

  // Sort and show after
  rankedResults.sort((a,b) => b.score - a.score);

  console.log('\n--- After Re-Ranking (top 5) ---');
  for (let i = 0; i < Math.min(5, rankedResults.length); i++) {
    const r = rankedResults[i];
    console.log(\`[\${i}] score=\${r.score.toFixed(4)} source=\${r.source} lastModified=\${r.lastModified || 'N/A'}\`);
  }

  // Check if any intent-detector result is in top 3
  const top3 = rankedResults.slice(0, 3).map(r => r.source);
  console.log('\nTop 3 sources:', top3.join(', '));

  const hasIntentDetector = top3.some(s => s.includes('intent-detector'));
  if (hasIntentDetector) {
    console.log('✅ intent-detector found in top 3!');
  } else {
    // Check all results for any intent-detector entry
    const allResults = rankedResults.filter(r => r.source && r.source.includes('intent-detector'));
    if (allResults.length > 0) {
      console.log('ℹ️  intent-detector found but not in top 3:');
      for (const r of allResults) {
        console.log(\`   score=\${r.score.toFixed(4)} source=\${r.source} lastModified=\${r.lastModified}\`);
      }
    } else {
      console.log('ℹ️  No intent-detector results in Qdrant (only test file exists)');
    }
  }
}

main().catch(e => console.error(e.message));
